import theme from 'theme'

const styles = {
  gridItem: {
    backgroundColor: '#F5F5F5',
    padding: theme.spacing(1),
    marginTop: theme.spacing(1),
    marginLeft: theme.spacing(1)
  },
  small: {
    maxWidth: '47%'
  },
  button: {
    padding: '0px'
  },
  listado: {
    paddingLeft: '0px',
    fontSize: '12px'
  },
  input: {
    width: '100px',
    marginTop: '-10px'
  },
  tooltip: {
    marginLeft: theme.spacing(0.5),
    float: 'left'
  },
  info: {
    height: '17px',
    width: '17px'
  },
  title: {
    float: 'left',
    display: 'inline'
  },
  link: {
    color: '#0532ff !important',
    fontSize: '12px'
  },
  card: {
    minHeight: '103px',
    backgroundColor: '#F5F5F5',
    padding: theme.spacing(1.5),
    marginTop: theme.spacing(1),
    marginLeft: theme.spacing(1)
  },
  noAffectation: {
    marginTop: theme.spacing(1),
    marginLeft: theme.spacing(1)
  }
}

export default styles
